import React, { useState, useEffect } from 'react';
import Graph from './Graph';
import { pointAPI, authAPI } from './api';

function MainPage({ onLogout }) {
  // Состояние формы - по ТЗ
  const [selectedX, setSelectedX] = useState([]); // Checkbox для X
  const [y, setY] = useState(''); // Text input для Y
  const [selectedR, setSelectedR] = useState([]); // Checkbox для R

  // Состояние приложения
  const [results, setResults] = useState([]);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [username, setUsername] = useState('');

  // Варианты по ТЗ
  const xOptions = [-5, -4, -3, -2, -1, 0, 1, 2, 3];
  const rOptions = [-5, -4, -3, -2, -1, 0, 1, 2, 3]; // По ТЗ, но радиус отрицательным не может быть!

  // Текущий R для графика (берем первый выбранный)
  const currentR = selectedR.length > 0 ? parseFloat(selectedR[0]) : null;

  useEffect(() => {
    loadResults();
    const savedUsername = localStorage.getItem('username');
    if (savedUsername) {
      setUsername(savedUsername);
    }
  }, []);

  const loadResults = async () => {
    const result = await pointAPI.getResults();
    if (result.success) {
      setResults(result.data);
    }
  };

  // Обработчики для checkbox
  const handleXChange = (value) => {
    setSelectedX(prev =>
      prev.includes(value)
        ? prev.filter(v => v !== value)
        : [...prev, value]
    );
  };

  const handleRChange = (value) => {
    // Для радиуса обычно выбирают один вариант
    setSelectedR(prev =>
      prev.includes(value)
        ? prev.filter(v => v !== value)
        : [value]
    );
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    // Валидация
    if (selectedX.length === 0 || !y || selectedR.length === 0) {
      setError('Заполните все поля');
      return;
    }

    const yNum = parseFloat(y);
    if (isNaN(yNum)) {
      setError('Y должен быть числом');
      return;
    }

    if (yNum < -5 || yNum > 5) {
      setError('Y должен быть в диапазоне от -5 до 5');
      return;
    }

    // Берем первый выбранный R (по ТЗ checkbox, но радиус один)
    const rNum = parseFloat(selectedR[0]);

    // Проверка радиуса (не может быть отрицательным)
    if (rNum <= 0) {
      setError('Радиус должен быть положительным');
      return;
    }

    setLoading(true);

    // Проверяем все выбранные X
    const newResults = [];
    for (const xValue of selectedX) {
      const result = await pointAPI.checkPoint(parseFloat(xValue), yNum, rNum);
      if (result.success) {
        newResults.push(result.data);
      } else {
        setError(`Ошибка для X=${xValue}: ${result.message}`);
        break;
      }
    }

    setLoading(false);

    if (newResults.length > 0) {
      // Добавляем новые результаты
      setResults(prev => [...newResults, ...prev]);
      // Очищаем только Y (X и R остаются выбранными)
      setY('');
    }
  };

  const handleClearResults = async () => {
    if (window.confirm('Очистить историю проверок?')) {
      const result = await pointAPI.clearResults();
      if (result.success) {
        setResults([]);
      }
    }
  };

  const handleLogout = async () => {
    await authAPI.logout();
    onLogout();
  };

  const handleCanvasClick = async (clickX, clickY) => {
    if (selectedR.length === 0) {
      alert('Сначала выберите радиус R');
      return;
    }

    const rNum = parseFloat(selectedR[0]);
    const result = await pointAPI.checkPoint(clickX, clickY, rNum);

    if (result.success) {
      setResults(prev => [result.data, ...prev]);
    }
  };

  return (
    <div className="main-container">
      <header className="header">
        <div>
          <h1>Проверка попадания точки в область</h1>
          <p>Студент: Ваше ФИО | Группа: PXXXX | Вариант: XXXX</p>
          <p>Пользователь: {username}</p>
        </div>
        <button onClick={handleLogout} className="logout-btn">
          Выйти
        </button>
      </header>

      <div className="content">
        {/* Левая часть - форма */}
        <div className="form-section">
          <form onSubmit={handleSubmit} className="point-form">
            <h2>Введите координаты</h2>

            {/* X: Checkbox группа */}
            <div className="form-group">
              <label>Координата X (checkbox):</label>
              <div className="checkbox-group">
                {xOptions.map(value => (
                  <label key={value} className="checkbox-label">
                    <input
                      type="checkbox"
                      value={value}
                      checked={selectedX.includes(value.toString())}
                      onChange={() => handleXChange(value.toString())}
                    />
                    {value}
                  </label>
                ))}
              </div>
              {selectedX.length > 0 && (
                <small>Выбрано: {selectedX.join(', ')}</small>
              )}
            </div>

            {/* Y: Text input */}
            <div className="form-group">
              <label htmlFor="y">Координата Y (text):</label>
              <input
                type="number"
                id="y"
                value={y}
                onChange={(e) => setY(e.target.value)}
                placeholder="-5 ... 5"
                min="-5"
                max="5"
                step="0.1"
                required
              />
              <small>Диапазон: от -5 до 5</small>
            </div>

            {/* R: Checkbox группа */}
            <div className="form-group">
              <label>Радиус R (checkbox):</label>
              <div className="checkbox-group">
                {rOptions.map(value => (
                  <label key={value} className="checkbox-label">
                    <input
                      type="checkbox"
                      value={value}
                      checked={selectedR.includes(value.toString())}
                      onChange={() => handleRChange(value.toString())}
                    />
                    {value}
                  </label>
                ))}
              </div>
              {selectedR.length > 0 && (
                <small>Выбран R: {selectedR[0]}</small>
              )}
              <small style={{color: 'orange', display: 'block', marginTop: '5px'}}>
                *По ТЗ checkbox от -5 до 3, но радиус не может быть ≤ 0
              </small>
            </div>

            {error && <div className="error-message">{error}</div>}

            <button
              type="submit"
              className="submit-btn"
              disabled={loading || selectedX.length === 0 || !y || selectedR.length === 0}
            >
              {loading ? 'Проверка...' : 'Проверить'}
            </button>
          </form>

          <div className="action-buttons">
            <button
              onClick={handleClearResults}
              className="clear-btn"
              disabled={results.length === 0}
            >
              Очистить историю
            </button>
          </div>
        </div>

        {/* Правая часть - график и таблица */}
        <div className="graph-section">
          <Graph
            results={results}
            currentR={currentR}
            onCanvasClick={handleCanvasClick}
          />

          <div className="results-section">
            <h2>История проверок ({results.length})</h2>
            {results.length === 0 ? (
              <p className="no-results">Нет результатов. Проверьте точку!</p>
            ) : (
              <table className="results-table">
                <thead>
                  <tr>
                    <th>X</th>
                    <th>Y</th>
                    <th>R</th>
                    <th>Результат</th>
                    <th>Время</th>
                  </tr>
                </thead>
                <tbody>
                  {results.map((result, index) => (
                    <tr key={index} className={result.hit ? 'hit-row' : 'miss-row'}>
                      <td>{result.x.toFixed(2)}</td>
                      <td>{result.y.toFixed(2)}</td>
                      <td>{result.r}</td>
                      <td>
                        <span className={result.hit ? 'hit' : 'miss'}>
                          {result.hit ? '✓ Попадание' : '✗ Промах'}
                        </span>
                      </td>
                      <td>
                        {result.createdAt ?
                          new Date(result.createdAt).toLocaleTimeString('ru-RU') :
                          '--:--:--'}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

export default MainPage;
